"use client"

import { FileText, ImageIcon, File } from "lucide-react"
import type { Informe, Contrato, Actividad, Aporte, Evidencia } from "@/lib/types"
import { format, parseISO } from "date-fns"
import { es } from "date-fns/locale"

interface ReportPreviewProps {
  informe: Informe
  contrato: Contrato
  actividades: Actividad[]
  aportes: Aporte[]
  evidencias: Evidencia[]
}

function getEvidenciaIcon(tipo: Evidencia["tipo"]) {
  switch (tipo) {
    case "imagen":
      return ImageIcon
    case "pdf":
      return FileText
    default:
      return File
  }
}

export function ReportPreview({
  informe,
  contrato,
  actividades,
  aportes,
  evidencias,
}: ReportPreviewProps) {
  const periodAportes = aportes.filter((a) => {
    const fecha = new Date(a.fecha)
    return (
      fecha >= new Date(informe.fechaInicio) &&
      fecha <= new Date(informe.fechaFin)
    )
  })

  return (
    <div className="rounded-lg border border-border bg-card" id="report-content">
      <div className="border-b border-border p-6">
        <div className="flex flex-col items-center gap-2 text-center">
          <div className="flex h-12 w-12 items-center justify-center rounded-lg bg-primary/10">
            <FileText className="h-6 w-6 text-primary" />
          </div>
          <h1 className="text-lg font-bold text-card-foreground">
            INFORME DE ACTIVIDADES
          </h1>
          <p className="text-sm font-medium text-primary">
            {informe.periodo}
          </p>
        </div>
      </div>

      <div className="border-b border-border p-6">
        <h2 className="mb-3 text-sm font-semibold text-card-foreground uppercase tracking-wide">
          Informacion del Contrato
        </h2>
        <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
          <div>
            <p className="text-xs text-muted-foreground">Contrato No.</p>
            <p className="text-sm font-medium text-card-foreground">
              {contrato.numero}
            </p>
          </div>
          <div>
            <p className="text-xs text-muted-foreground">Entidad</p>
            <p className="text-sm font-medium text-card-foreground">
              {contrato.entidad}
            </p>
          </div>
          <div>
            <p className="text-xs text-muted-foreground">Contratista</p>
            <p className="text-sm font-medium text-card-foreground">
              {contrato.contratistaNombre}
            </p>
          </div>
          <div>
            <p className="text-xs text-muted-foreground">Periodo del informe</p>
            <p className="text-sm font-medium text-card-foreground">
              {format(parseISO(informe.fechaInicio), "d 'de' MMMM", {
                locale: es,
              })}{" "}
              al{" "}
              {format(parseISO(informe.fechaFin), "d 'de' MMMM 'de' yyyy", {
                locale: es,
              })}
            </p>
          </div>
          <div className="sm:col-span-2">
            <p className="text-xs text-muted-foreground">Objeto</p>
            <p className="text-sm text-card-foreground leading-relaxed">
              {contrato.objeto}
            </p>
          </div>
        </div>
      </div>

      <div className="p-6">
        <h2 className="mb-4 text-sm font-semibold text-card-foreground uppercase tracking-wide">
          Actividades y Aportes del Periodo
        </h2>
        <div className="flex flex-col gap-6">
          {actividades.map((actividad) => {
            const actAportes = periodAportes.filter(
              (a) => a.actividadId === actividad.id
            )
            const actEvidencias = evidencias.filter(
              (e) => e.actividadId === actividad.id
            )

            return (
              <div
                key={actividad.id}
                className="rounded-md border border-border p-4"
              >
                <div className="mb-3 flex items-center gap-2">
                  <span className="flex h-6 w-6 items-center justify-center rounded bg-primary/10 text-xs font-bold text-primary">
                    {actividad.numero}
                  </span>
                  <h3 className="text-sm font-semibold text-card-foreground">
                    {actividad.titulo}
                  </h3>
                  <span className="ml-auto text-xs text-muted-foreground">
                    Peso: {actividad.porcentajePeso}%
                  </span>
                </div>

                {actAportes.length === 0 ? (
                  <p className="text-xs italic text-muted-foreground">
                    Sin aportes en este periodo
                  </p>
                ) : (
                  <div className="flex flex-col gap-2">
                    {actAportes.map((aporte) => (
                      <div
                        key={aporte.id}
                        className="rounded bg-muted/40 px-3 py-2"
                      >
                        <p className="mb-0.5 text-xs font-medium text-primary">
                          {format(
                            parseISO(aporte.fecha),
                            "d 'de' MMMM, yyyy",
                            { locale: es }
                          )}
                        </p>
                        <p className="text-sm text-card-foreground leading-relaxed">
                          {aporte.descripcion}
                        </p>
                      </div>
                    ))}
                  </div>
                )}

                {actEvidencias.length > 0 && (
                  <div className="mt-3 border-t border-border pt-3">
                    <p className="mb-2 text-xs font-medium text-muted-foreground">
                      Evidencias:
                    </p>
                    <div className="flex flex-wrap gap-2">
                      {actEvidencias.map((ev) => {
                        const Icon = getEvidenciaIcon(ev.tipo)
                        return (
                          <span
                            key={ev.id}
                            className="flex items-center gap-1.5 rounded bg-muted px-2 py-1 text-xs text-muted-foreground"
                          >
                            <Icon className="h-3 w-3" />
                            {ev.nombre}
                          </span>
                        )
                      })}
                    </div>
                  </div>
                )}
              </div>
            )
          })}
        </div>
      </div>

      <div className="border-t border-border p-6">
        <div className="grid grid-cols-1 gap-8 sm:grid-cols-2">
          <div className="flex flex-col items-center gap-1 text-center">
            <div className="mb-4 h-px w-48 bg-foreground/30" />
            <p className="text-sm font-medium text-card-foreground">
              {contrato.contratistaNombre}
            </p>
            <p className="text-xs text-muted-foreground">
              {contrato.contratistaProfesion}
            </p>
            <p className="text-xs text-muted-foreground">
              C.C. {contrato.contratistaCedula}
            </p>
          </div>
          <div className="flex flex-col items-center gap-1 text-center">
            <div className="mb-4 h-px w-48 bg-foreground/30" />
            <p className="text-sm font-medium text-card-foreground">
              {contrato.supervisorNombre}
            </p>
            <p className="text-xs text-muted-foreground">
              {contrato.supervisorCargo}
            </p>
          </div>
        </div>
      </div>
    </div>
  )
}
