"use client"

import { use, useState, useCallback } from "react"
import Link from "next/link"
import {
  ArrowLeft,
  Download,
  Send,
  CheckCircle2,
} from "lucide-react"
import { PageHeader } from "@/components/page-header"
import { ReportPreview } from "@/components/report-preview"
import {
  getInforme,
  getContrato,
  getActividades,
  getAportes,
  getEvidencias,
  updateInforme,
} from "@/lib/store"
import { toast } from "sonner"
import type { EstadoInforme } from "@/lib/types"

const estadoBadge: Record<
  EstadoInforme,
  { label: string; className: string }
> = {
  borrador: {
    label: "Borrador",
    className: "bg-muted text-muted-foreground",
  },
  finalizado: {
    label: "Finalizado",
    className: "bg-chart-2/15 text-chart-2",
  },
  enviado: {
    label: "Enviado",
    className: "bg-chart-1/15 text-chart-1",
  },
}

export default function InformeDetailPage({
  params,
}: {
  params: Promise<{ id: string }>
}) {
  const { id } = use(params)
  const [version, setVersion] = useState(0)
  const refresh = useCallback(() => setVersion((v) => v + 1), [])

  void version
  const informe = getInforme(id)
  const contrato = getContrato()
  const actividades = getActividades()
  const aportes = getAportes()
  const evidencias = getEvidencias()

  if (!informe) {
    return (
      <div className="flex flex-col items-center gap-4 py-16">
        <p className="text-sm font-medium text-foreground">
          Informe no encontrado
        </p>
        <Link
          href="/informes"
          className="text-sm text-primary hover:underline"
        >
          Volver a informes
        </Link>
      </div>
    )
  }

  const badge = estadoBadge[informe.estado]

  function handleFinalize() {
    updateInforme(id, { estado: "finalizado" })
    toast.success("Informe marcado como finalizado")
    refresh()
  }

  function handleSend() {
    updateInforme(id, { estado: "enviado" })
    toast.success("Informe marcado como enviado")
    refresh()
  }

  function handleDownload() {
    toast.info("Descarga simulada - En produccion se generaria el PDF")
  }

  return (
    <div className="flex flex-col gap-6">
      <Link
        href="/informes"
        className="flex items-center gap-1.5 text-sm text-muted-foreground hover:text-foreground"
      >
        <ArrowLeft className="h-4 w-4" />
        Volver a informes
      </Link>

      <PageHeader titulo={`Informe - ${informe.periodo}`}>
        <span
          className={`rounded-full px-3 py-1 text-xs font-medium ${badge.className}`}
        >
          {badge.label}
        </span>
      </PageHeader>

      <div className="flex flex-wrap items-center gap-2">
        {informe.estado === "borrador" && (
          <button
            onClick={handleFinalize}
            className="flex items-center gap-2 rounded-md bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90"
          >
            <CheckCircle2 className="h-4 w-4" />
            Finalizar Informe
          </button>
        )}
        {informe.estado === "finalizado" && (
          <button
            onClick={handleSend}
            className="flex items-center gap-2 rounded-md bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90"
          >
            <Send className="h-4 w-4" />
            Marcar como Enviado
          </button>
        )}
        <button
          onClick={handleDownload}
          className="flex items-center gap-2 rounded-md border border-border px-4 py-2 text-sm font-medium text-foreground transition-colors hover:bg-accent"
        >
          <Download className="h-4 w-4" />
          Descargar PDF
        </button>
      </div>

      <ReportPreview
        informe={informe}
        contrato={contrato}
        actividades={actividades}
        aportes={aportes}
        evidencias={evidencias}
      />
    </div>
  )
}
